import { type Ref, type RefCallback, type RefObject, useLayoutEffect, useRef } from 'react';

type OptionalRef<T> = Ref<T> | undefined;

type Cleanup = (() => void) & { isSynthetic?: boolean };

type MultiRef<T> = RefCallback<T> &
  RefObject<T | null> & {
    ref: RefObject<T | null>;
  };

export function setRef<T>(ref: OptionalRef<T>, value: T): Cleanup | undefined {
  if (typeof ref === 'function') {
    const cleanup = ref(value);

    if (typeof cleanup === 'function') {
      return cleanup;
    }
    const cl: Cleanup = () => ref(null);
    cl.isSynthetic = true;
    return cl;
  } else if (ref) {
    ref.current = value;
    const cl: Cleanup = () => (ref.current = null);
    cl.isSynthetic = true;
    return cl;
  }
  return undefined;
}

/**
 * Combines multiple refs (callback refs, ref objects, or `undefined`) into a
 * single stable ref callback that can be passed to a React element.
 *
 * **Features:**
 * - Accepts any mix of `RefObject`, callback refs, and `undefined`.
 * - Returns a **stable** function identity — safe to pass as a JSX `ref` prop
 *   without causing extra attach/detach cycles.
 * - Granular diffing: when the set of refs changes between renders, only the
 *   added/removed refs are set/cleaned up — stable refs are left untouched.
 * - Supports React 19 ref cleanup functions. If at least one callback ref
 *   returns a cleanup, the combined ref returns a cleanup too. If none do, no
 *   cleanup is returned, keeping the hook compatible with **React 18** (which
 *   warns when a ref callback returns a value).
 * - Exposes `.current` (the last set value) and `.ref` (a `RefObject`
 *   pointing to the same value) for imperative access.
 *
 * **Known limitations:**
 * - When refs change, the diff runs inside a `useLayoutEffect`. Consumer layout
 *   effects declared *before* the hook may therefore see stale ref values for
 *   newly added refs on the same render (initial mount is unaffected since the
 *   ref callback runs before all layout effects). To avoid this, declare consumer
 *   layout effects *after* the hook.
 * - If refs *and* the underlying element change in the same commit, removed
 *   refs may be transiently called with the new element before the layout
 *   effect cleans them up. The final state is always correct.
 *
 * @example
 * ```tsx
 * const MyComponent = forwardRef<HTMLDivElement>((props, forwardedRef) => {
 *   const localRef = useRef<HTMLDivElement>(null);
 *   const combinedRef = useCombinedRefs(forwardedRef, localRef);
 *   return <div ref={combinedRef} />;
 * });
 * ```
 */
export function useCombinedRefs<T>(...refs: OptionalRef<T>[]) {
  type Store = [value: T | null, refs: OptionalRef<T>[], cleanupMap: Map<OptionalRef<T>, Cleanup>, refFn: MultiRef<T>];

  const storeRef = useRef<Store | null>(null);

  if (storeRef.current === null) {
    const refFn = function combinedRef(value: T | null) {
      const cleanupMap = store[2];

      for (const cleanup of cleanupMap.values()) cleanup?.();
      cleanupMap.clear();

      store[0] = value;

      let hasCleanup = false;

      if (value !== null) {
        for (const r of store[1]) {
          const cleanup = setRef(r, value);
          if (!cleanup?.isSynthetic) hasCleanup = true;
          if (typeof cleanup === 'function') cleanupMap.set(r, cleanup);
        }
      }

      if (!hasCleanup) return;

      return () => {
        store[0] = null;
        for (const cleanup of store[2].values()) cleanup?.();
        store[2].clear();
      };
    } as MultiRef<T>;

    Object.defineProperty(refFn, 'current', {
      get() {
        return store[0];
      },
    });

    Object.defineProperty(refFn, 'ref', {
      value: Object.defineProperty({} as RefObject<T | null>, 'current', {
        get() {
          return store[0];
        },
      }),
    });

    storeRef.current = [null, refs, new Map(), refFn];
  }

  const store = storeRef.current!;

  // Diff refs on committed renders only (immune to concurrent mode interruptions)
  useLayoutEffect(() => {
    const value = store[0];
    const prevRefs = store[1];
    store[1] = refs;

    if (value === null) return;
    if (prevRefs.length === refs.length && prevRefs.every((r, i) => r === refs[i])) return;

    const cleanupMap = store[2];
    const prevSet = new Set(prevRefs);
    const nextSet = new Set(refs);

    for (const r of prevRefs) {
      if (!nextSet.has(r)) {
        cleanupMap.get(r)?.();
        cleanupMap.delete(r);
      }
    }

    for (const r of refs) {
      if (!prevSet.has(r)) {
        const cleanup = setRef(r, value);
        if (typeof cleanup === 'function') cleanupMap.set(r, cleanup);
      }
    }
  });

  return store[3];
}
